// ─── Story Starter Prompted Frameworks ────────────────────────────────────────
//
// Source of truth for the Story Starter wizard.
// Each framework has:
//   displayName  — short label
//   tagline      — one-line description shown in wizard
//   premise      — 3–4 questions to extract the core idea before beats begin
//   beats        — array of beat objects, each with:
//                    beat        — name of the beat (matches FRAMEWORK_BEATS)
//                    act         — act number (1/2/3 or equivalent)
//                    prompt      — the question the user is answering
//                    hint        — the craft principle behind this beat
//                    placeholder — sample text to spark thinking
//
// Import in Story Starter wizard and Beat Tracker guidance panels.

export const FRAMEWORK_GUIDED_PROMPTS = {

  // ─── Save the Cat ───────────────────────────────────────────────────────────
  'save-the-cat': {
    displayName: 'Save the Cat',
    tagline: 'Blake Snyder\'s 15-beat Hollywood structure',
    premise: [
      { id: 'logline',     label: 'Your one-liner',                          hint: 'Who is your protagonist, what do they want, and what stands in their way?',                                   placeholder: 'A burned-out detective discovers her missing sister is running the cartel she\'s investigating.' },
      { id: 'theme',       label: 'What question does this story ask?',       hint: 'Not what it answers — what it asks. A theme is an unresolved tension, not a moral.',                         placeholder: 'Can you save someone who doesn\'t want to be saved?' },
      { id: 'genre',       label: 'What genre is this and what does that promise?', hint: 'Genre sets audience expectation. A thriller promises dread; a romance promises connection.',          placeholder: 'It\'s a thriller, so the audience expects escalating danger and a climactic confrontation.' },
      { id: 'save_the_cat',label: 'How will the audience like your protagonist early?', hint: 'Blake Snyder\'s core principle: show them doing something generous, funny, or brave before you ask us to follow them into danger.', placeholder: 'She pulls over to help an old man whose car has broken down, even though she\'s late to a briefing.' },
    ],
    beats: [
      { beat: 'Opening Image',           act: 1, prompt: 'What single image opens your story — a compressed picture of your protagonist\'s world before anything changes?',                                     hint: 'This is the mirror of your Final Image. Show "stuck." The audience should feel the weight of who this person is right now.',                                                              placeholder: 'We open on her alone in the precinct at midnight, surrounded by case files she\'ll never close.' },
      { beat: 'Theme Stated',            act: 1, prompt: 'Who says something to your protagonist that contains the theme — and which they completely dismiss or misunderstand?',                                  hint: 'This line should land as throwaway in Act 1. By the end of Act 3, the audience will hear it differently. It\'s a seed, not a lecture.',                                                    placeholder: 'Her partner says: "You can\'t help people who don\'t want to be found." She rolls her eyes.' },
      { beat: 'Set-Up',                  act: 1, prompt: 'What people, flaws, habits, and circumstances need to be established — and will need to be "fixed" by the end?',                                       hint: 'Introduce all the things that will transform. Every element you plant here should pay off in the Finale.',                                                                                  placeholder: 'Her estrangement from her sister, her lone-wolf approach, her distrust of the department.' },
      { beat: 'Catalyst',                act: 1, prompt: 'What event happens TO your protagonist around page 12 that disrupts their world?',                                                                      hint: 'The Catalyst arrives from outside. It is done to the protagonist, not chosen by them. This is not their decision — it\'s the world forcing a new situation.',                              placeholder: 'A body turns up with her sister\'s ID. Her sister has been dead — officially — for three years.' },
      { beat: 'Debate',                  act: 1, prompt: 'What internal question does your protagonist wrestle with before committing to Act 2?',                                                                  hint: 'The Debate is visible hesitation. What fear holds them back? What is the cost of crossing this threshold?',                                                                                 placeholder: 'Does she open this case and expose her sister, or close it and protect what\'s left of her family?' },
      { beat: 'Break into Two',          act: 1, prompt: 'What active choice does your protagonist make that launches them into Act 2\'s world?',                                                                  hint: 'The most critical beat in the script. The protagonist CHOOSES. They walk through the door. It must be their decision, and it must be irreversible.',                                        placeholder: 'She pulls the case file, works it alone, and files a false report to buy herself time.' },
      { beat: 'B Story',                 act: 2, prompt: 'Who is the secondary character that enters Act 2 — and what relationship will carry the theme?',                                                         hint: 'The B Story is almost always a relationship. It\'s where the theme lives explicitly. The protagonist learns the truth of the Theme Stated through this person.',                           placeholder: 'Her sister\'s old handler — someone who\'s been protecting her all along — surfaces and offers to help.' },
      { beat: 'Fun and Games',           act: 2, prompt: 'What does the audience came to see? What is the "promise of the premise" playing out in full?',                                                          hint: 'This is the upside of the new world. Before things get hard, we get the thing the logline promised. It\'s called "Fun and Games" because it should feel like the story is working.',     placeholder: 'She infiltrates the network, gets closer to her sister, and for the first time in years they talk on the phone.' },
      { beat: 'Midpoint',                act: 2, prompt: 'What false victory or false defeat shifts the entire act at the halfway mark?',                                                                          hint: 'False victory (they think they\'ve won) or false defeat (they think they\'ve lost). Either way, the stakes escalate and the protagonist becomes fully active, not reactive.',              placeholder: 'She finds her sister — alive, in control, and orders her to walk away. False defeat: everything she feared is true.' },
      { beat: 'Bad Guys Close In',       act: 2, prompt: 'How do external pressure and internal doubt begin dismantling everything built in Fun and Games?',                                                        hint: 'External enemies tighten the net. Internal enemies — the protagonist\'s own doubts, flaws, loyalties — amplify the damage. Both tracks converge.',                                          placeholder: 'Her department is compromised. Her sister goes dark. Her partner is killed. She\'s the only one who knows the truth.' },
      { beat: 'All Is Lost',             act: 2, prompt: 'What is the lowest point — and what literal or symbolic death happens here?',                                                                             hint: 'Someone or something must die. A relationship, a belief, an identity. The protagonist\'s old world is gone. The new one is not yet built. This is the void.',                               placeholder: 'She\'s suspended from the department. Her sister burns her one alibi. A mentor is killed on her behalf.' },
      { beat: 'Dark Night of the Soul',  act: 2, prompt: 'How does your protagonist sit in the wreckage — and what internal resource do they finally find?',                                                        hint: 'The protagonist is alone with what they\'ve done and who they\'ve been. The solution cannot come from outside. It must come from who they now are.',                                        placeholder: 'She stops trying to save her sister and decides to stop the cartel regardless of what it costs her family.' },
      { beat: 'Break into Three',        act: 3, prompt: 'How do the A and B stories merge — and where does the idea for the Finale actually come from?',                                                           hint: 'The B Story resolves into the A Story. The protagonist\'s new insight — earned through the relationship of the B Story — becomes the key to the Finale.',                                   placeholder: 'Her sister\'s handler reveals a piece of evidence her sister planted years ago. She built her own exit. Now it\'s hers to use.' },
      { beat: 'Finale',                  act: 3, prompt: 'How does your protagonist execute the final plan using everything they\'ve learned — and how does it mirror but improve on the Set-Up?',                 hint: 'Mirror everything from Act 1. The flaws, the relationships, the objects — they all come back transformed. The protagonist succeeds not in spite of who they are but because of who they\'ve become.', placeholder: 'She uses the case files she never closed, the partner\'s contacts, and her sister\'s own evidence to expose the network from inside out.' },
      { beat: 'Final Image',             act: 3, prompt: 'What single image closes your story — the mirror opposite of the Opening Image?',                                                                         hint: 'Not just resolution — proof that change is permanent. What does "unstuck" look like for this person?',                                                                                      placeholder: 'She closes the last file. The precinct is full. Her sister\'s face is on a wall — not a suspect board. A memorial.' },
    ],
  },

  // ─── Hero's Journey ─────────────────────────────────────────────────────────
  'heros-journey': {
    displayName: "Hero's Journey",
    tagline: "Joseph Campbell's mythic structure — 12 stages",
    premise: [
      { id: 'hero',          label: 'Who is your hero before the journey begins?',         hint: 'Establish the Ordinary World: who they are, what they lack, and what they\'re avoiding.',        placeholder: 'A farmboy who dreams of something beyond his village but lacks the courage to leave.' },
      { id: 'call',          label: 'What calls them out of that world?',                  hint: 'The Call must disrupt something they cannot ignore. It should feel both dangerous and undeniable.', placeholder: 'A message arrives that only he can deliver — and the messenger is already dead.' },
      { id: 'wound',         label: 'What wound or belief holds them back at first?',      hint: 'The Refusal reveals character. What specific fear makes this particular hero hesitate?',          placeholder: 'He believes he\'s ordinary. That the world doesn\'t need him and he\'ll only make things worse.' },
      { id: 'elixir',        label: 'What will the hero bring back at the end?',           hint: 'The Elixir is what the journey was for — wisdom, healing, freedom. Name it now so the journey earns it.', placeholder: 'He returns with the knowledge that ordinary people are the only ones who can change the world.' },
    ],
    beats: [
      { beat: 'Ordinary World',            act: 1, prompt: 'What does the hero\'s normal life look like — and what is already missing or incomplete in it?',                                                       hint: 'Show what the hero stands to lose. The Ordinary World must be real enough to feel like home before it\'s left behind.',                                                                     placeholder: 'He works the fields alone. His family expects nothing of him. He reads old maps by firelight and wonders.' },
      { beat: 'Call to Adventure',         act: 1, prompt: 'What disrupts the Ordinary World and presents the challenge ahead?',                                                                                   hint: 'The Call comes from outside. It doesn\'t have to be dramatic — it has to be impossible to ignore.',                                                                                        placeholder: 'A stranger arrives injured with a sealed letter. Her last words are his name.' },
      { beat: 'Refusal of the Call',       act: 1, prompt: 'Why does the hero initially refuse or hesitate? What specific fear drives the refusal?',                                                               hint: 'The refusal makes the hero human. It also raises stakes — we understand what crossing the threshold will cost.',                                                                           placeholder: 'He buries the letter. He\'s nobody. Whatever this is, it belongs to someone else.' },
      { beat: 'Meeting the Mentor',        act: 1, prompt: 'Who gives the hero wisdom, a tool, or the push they need to cross the threshold?',                                                                      hint: 'The Mentor doesn\'t solve the problem — they equip the hero and send them forward. The wisdom they give will matter most at the story\'s darkest point.',                                  placeholder: 'The village elder has been waiting for him. She gives him the map. She won\'t explain why.' },
      { beat: 'Crossing the Threshold',    act: 1, prompt: 'When does the hero commit? What is the point of no return?',                                                                                           hint: 'The Ordinary World is now behind them. Something happens that means they cannot go back unchanged. This is the moment the story truly begins.',                                             placeholder: 'He opens the letter. His village burns behind him as he reads it. He runs forward.' },
      { beat: 'Tests, Allies, Enemies',    act: 2, prompt: 'What obstacles, allies, and antagonists define the Special World? What rules does the hero have to learn?',                                            hint: 'This section builds the new world and populates it. Who can be trusted? Who can\'t? What does this world demand from the hero that their old world never did?',                            placeholder: 'He joins a group of outcasts — each one broken in a specific way that mirrors his own fracture.' },
      { beat: 'Approach to the Inmost Cave', act: 2, prompt: 'How does the hero prepare for the central ordeal? What is their plan — and what does it reveal about their remaining blind spot?',                   hint: 'The Approach is the last breath before the plunge. The hero believes they are ready. They are not — not fully. The plan will fail in a specific way that mirrors their core wound.',       placeholder: 'He makes a plan that relies on others trusting him. He doesn\'t tell them what he\'s walking into.' },
      { beat: 'The Ordeal',                act: 2, prompt: 'What is the central crisis — the point at which the hero must "die" to be reborn?',                                                                    hint: 'The Ordeal isn\'t just a fight. It\'s a death. Something fundamental about who the hero was cannot survive this moment. What dies here so something new can live?',                        placeholder: 'He is captured. His allies are scattered. The only way out requires him to ask for help.' },
      { beat: 'Reward',                    act: 2, prompt: 'What does the hero claim after surviving the Ordeal?',                                                                                                 hint: 'The Reward is earned, not given. It may be an object, knowledge, a relationship, or a new identity. It is the proof that the Ordeal changed something.',                                   placeholder: 'He finds the weapon — but more importantly he finds the people who had already been fighting for years.' },
      { beat: 'The Road Back',             act: 3, prompt: 'What drives the hero back toward the Ordinary World — and what final obstacle appears?',                                                                hint: 'The journey home is not safe. A final antagonistic force reappears. The hero must make one more choice.',                                                                                   placeholder: 'He turns back to his village. But the enemy followed. Everything he left behind is at risk again.' },
      { beat: 'Resurrection',              act: 3, prompt: 'What is the final transformation — the climactic moment that proves the hero has truly changed?',                                                       hint: 'The Resurrection is the hero applying everything they have become. The old hero could not have done this. Only the reborn one can.',                                                        placeholder: 'He stands alone. He doesn\'t run. He doesn\'t wait for a plan. He just starts.' },
      { beat: 'Return with the Elixir',    act: 3, prompt: 'What does the hero bring back to the Ordinary World — and how does their return transform it?',                                                         hint: 'The Elixir heals something beyond the hero. Their transformation has a ripple effect. The world is genuinely different because they made the journey.',                                     placeholder: 'He returns with the knowledge that ordinary people built this resistance. He tells them. They believe it.' },
    ],
  },

  // ─── Story Circle ───────────────────────────────────────────────────────────
  'story-circle': {
    displayName: 'Story Circle',
    tagline: "Dan Harmon's 8-step emotional loop",
    premise: [
      { id: 'character',  label: 'Who is your protagonist in their comfort zone?',             hint: 'The Story Circle begins with someone established and comfortable. What does their normal look like?',  placeholder: 'A woman who has rebuilt a controlled, ordered life after a loss she never fully processed.' },
      { id: 'want',       label: 'What do they want that they cannot get in that comfort zone?', hint: 'The Want must require leaving safety. If they could get it without going anywhere, there\'s no circle.', placeholder: 'She wants to feel something again. Not grief — connection. But real connection requires risk.' },
      { id: 'price',      label: 'What will getting it cost them?',                             hint: 'The price is what makes the circle meaningful. The thing they get comes with a cost that changes them.', placeholder: 'Opening up means revisiting the loss. She\'ll have to grieve what she\'s been organizing her life around.' },
      { id: 'change',     label: 'Who are they when the circle closes?',                        hint: 'Not better or worse — different. How specifically has the journey transformed them?',                   placeholder: 'She\'s still organized, still careful. But now she\'s choosing it, not hiding in it.' },
    ],
    beats: [
      { beat: 'You',      act: 1, prompt: 'Who is your character in their comfort zone — their established self, their habits, their world?',                                                                    hint: 'Establish the "before." The audience needs to understand who this person is before anything disrupts them. Show the zone of comfort specifically.',                                         placeholder: 'She color-codes her calendar, answers emails by 7am, hasn\'t been late since 2019.' },
      { beat: 'Need',     act: 1, prompt: 'What does the character need or want that they cannot find in their current world?',                                                                                   hint: 'The Need is what puts the circle in motion. It may be stated plainly or shown through behavior. It doesn\'t have to be conscious — the character may not know they want it yet.',          placeholder: 'She keeps a photo in her desk drawer she never looks at. She never throws it away either.' },
      { beat: 'Go',       act: 1, prompt: 'What threshold do they cross into something new and unfamiliar?',                                                                                                      hint: 'The Go is the departure. Something pulls or pushes them out of the comfort zone and into territory that does not follow the old rules.',                                                   placeholder: 'Her company sends her to run a satellite office in a city she fled ten years ago.' },
      { beat: 'Search',   act: 2, prompt: 'What obstacles, detours, and failures define the road of trials in the unfamiliar world?',                                                                             hint: 'The Search is messy and uncomfortable. Things don\'t work the way they worked at home. The character\'s usual tools fail them in specific ways.',                                           placeholder: 'She tries to manage the office the way she manages everything. Her methods alienate the team.' },
      { beat: 'Find',     act: 2, prompt: 'Do they find what they were looking for? What complication or cost arrives with it?',                                                                                  hint: 'They get something — but not cleanly. The Find comes tangled with consequence. This is the midpoint of the circle.',                                                                       placeholder: 'She reconnects with someone from before. The connection is real. It\'s also reopening everything she sealed.' },
      { beat: 'Take',     act: 2, prompt: 'What does the character sacrifice, lose, or have to give up for what they found?',                                                                                     hint: 'The price is paid here. The circle demands a cost. Something must be surrendered for the transformation to be real.',                                                                      placeholder: 'She gives up her transfer home. She stops running. She calls her family for the first time in six years.' },
      { beat: 'Return',   act: 3, prompt: 'How does the character return to the familiar world — and how is the return different from the departure?',                                                             hint: 'The return is not a retreat. They\'re going back changed. The familiar world looks different now because they are different.',                                                              placeholder: 'She goes back to her old city — same offices, same routines. But she\'s not hiding in them.' },
      { beat: 'Change',   act: 3, prompt: 'How has the character fundamentally changed? What is different about who they are now?',                                                                                hint: 'The circle closes but the person has shifted. The transformation should be legible in their behavior, not stated in dialogue.',                                                             placeholder: 'The photo is on her desk now. She looks at it. Sometimes she smiles.' },
    ],
  },

  // ─── Sequence Approach ──────────────────────────────────────────────────────
  'sequence-approach': {
    displayName: 'Sequence Approach',
    tagline: '8 sequences, each with its own tension arc',
    premise: [
      { id: 'protagonist',  label: 'Who is your protagonist and what do they want most?',       hint: 'Identify the central dramatic want that drives the full 120 pages.',                                   placeholder: 'A forensic accountant who wants to prove her father didn\'t die in debt — he was murdered for what he knew.' },
      { id: 'obstacle',     label: 'What is the central obstacle between them and that want?',   hint: 'The obstacle must be present across all 8 sequences, even if its shape changes.',                      placeholder: 'The people who killed him control the financial system she\'s trying to audit.' },
      { id: 'midpoint',     label: 'What is the midpoint reversal — the moment that divides the film in two?', hint: 'The Sequence Approach hinges on a precise midpoint. What is the false victory or defeat that changes the game at pp. 60?', placeholder: 'She finds the proof — but it\'s in a format the court won\'t accept. She\'s further from justice than when she started.' },
      { id: 'question',     label: 'What central dramatic question drives Sequences 1-6?',       hint: 'The CDA is what the audience is asking. It should be answerable with yes or no.',                       placeholder: 'Will she prove her father was murdered before they silence her too?' },
    ],
    beats: [
      { beat: 'Sequence 1', act: 1, prompt: 'What establishes the world and protagonist — and where does the inciting incident land? (pp. 1–15)',                                                                 hint: 'Sequence 1 sets the world and plants the problem. The inciting incident arrives at the end of this sequence and forces a response.',                                                       placeholder: 'We meet her at her father\'s estate sale. She finds a discrepancy in a single line item.' },
      { beat: 'Sequence 2', act: 1, prompt: 'What is the protagonist\'s decision in response to the inciting incident — and how does it cross the point of no return? (pp. 15–30)',                               hint: 'Sequence 2 ends at Act 1\'s break. The protagonist commits to a course of action they cannot undo. This is the first irreversible choice.',                                               placeholder: 'She files a formal audit request — flagging herself to everyone her father was afraid of.' },
      { beat: 'Sequence 3', act: 2, prompt: 'How does the protagonist try old methods in the new situation — and where does the first significant setback land? (pp. 30–45)',                                      hint: 'Sequence 3 is "new world, old tools." The familiar approach meets an unfamiliar problem. It almost works. Then it doesn\'t.',                                                              placeholder: 'She follows standard audit procedures. They\'ve already moved everything. Standard procedure finds nothing.' },
      { beat: 'Sequence 4', act: 2, prompt: 'What real progress happens — and what midpoint reversal changes the game? (pp. 45–60)',                                                                               hint: 'The protagonist advances meaningfully, then the midpoint arrives. False victory or false defeat. The story pivots here.',                                                                   placeholder: 'She cracks a secondary ledger. Then the source she trusted turns out to be on their payroll.' },
      { beat: 'Sequence 5', act: 2, prompt: 'How does the midpoint\'s fallout escalate pressure and strip resources? (pp. 60–75)',                                                                                 hint: 'Post-midpoint, the antagonist becomes active. Resources — allies, time, credibility — get stripped. The protagonist must work with less.',                                                  placeholder: 'Her audit access is revoked. She\'s reassigned. She continues alone on personal time with no authorization.' },
      { beat: 'Sequence 6', act: 2, prompt: 'What is the lowest point — and what fundamental choice does the protagonist face before Act 3? (pp. 75–90)',                                                          hint: 'Sequence 6 is the All Is Lost beat and the choice that follows it. Something must die. Then the protagonist decides who they will be in Act 3.',                                            placeholder: 'Her source is killed. Her findings are destroyed. She can walk away or commit to something that will cost her everything.' },
      { beat: 'Sequence 7', act: 3, prompt: 'How does the protagonist act on their Act 2 choice and begin the final confrontation? (pp. 90–105)',                                                                  hint: 'Sequence 7 is the beginning of the climax. The protagonist is fully committed. They are doing — not reacting. Events accelerate.',                                                         placeholder: 'She leaks everything to two journalists simultaneously and attends the board meeting with a burner phone.' },
      { beat: 'Sequence 8', act: 3, prompt: 'How does the climax resolve — and what does the new state of the world look like? (pp. 105–120)',                                                                    hint: 'Sequence 8 resolves the central dramatic question and establishes the new order. What was broken is not necessarily fixed — but it is changed.',                                           placeholder: 'The board collapses. Her father\'s name is cleared. She resigns before they can fire her. She opens her own practice.' },
    ],
  },

  // ─── Fichtean Curve ─────────────────────────────────────────────────────────
  'fichtean': {
    displayName: 'Fichtean Curve',
    tagline: 'Start in crisis. Layer crises. End in resolution.',
    premise: [
      { id: 'protagonist',  label: 'Who is the protagonist — and what are they already dealing with when we meet them?',  hint: 'The Fichtean Curve opens in medias res. We meet the protagonist already under pressure.',                  placeholder: 'A surgeon mid-operation when her hand begins to shake uncontrollably for the first time.' },
      { id: 'core_conflict', label: 'What is the central conflict that all crises connect to?',                          hint: 'Each crisis must intensify the same wound. Name the core: what is this story ultimately about?',            placeholder: 'Whether she can continue to be who she has built herself to be, or must become someone entirely different.' },
      { id: 'climax',        label: 'What is the moment when all crises converge at once?',                              hint: 'The Fichtean climax feels inevitable in retrospect. Name the event where every thread lands simultaneously.', placeholder: 'She is in the OR when her diagnosis is confirmed in real time — and she finishes the surgery anyway.' },
      { id: 'backstory',     label: 'What backstory detail, revealed mid-story, recontextualizes everything?',           hint: 'In a Fichtean story, backstory is delivered as revelation, not exposition. What truth has the protagonist been hiding from themselves?', placeholder: 'She knew something was wrong six months ago. She never got tested. The crises are her punishment and her evasion.' },
    ],
    beats: [
      { beat: 'Opening Crisis',   act: 1, prompt: 'What crisis drops us into the middle of — with no preamble, no setup?',                                                                                        hint: 'No context. The audience will catch up. The opening crisis should feel like we\'ve entered something already in motion.',                                                                 placeholder: 'Her hand shakes mid-incision. She stabilizes it through sheer will. No one sees. The patient is fine. She is not.' },
      { beat: 'Crisis 1',         act: 1, prompt: 'What is the first escalating crisis — and what backstory fragment does it reveal?',                                                                             hint: 'Each crisis does two jobs: escalates pressure and reveals something. Crisis 1 is the first reveal — we begin to understand what this story is actually about.',                          placeholder: 'A colleague notices she\'s been scheduling her most complex cases in the mornings only. He asks. She deflects.' },
      { beat: 'Crisis 2',         act: 2, prompt: 'What is the second escalating crisis — worse than the first?',                                                                                                  hint: 'Tighten the spiral. Crisis 2 should close off an escape route that was available after Crisis 1.',                                                                                        placeholder: 'She drops a clamp. In front of residents. It\'s caught. Filed as "equipment malfunction" by the chief who covers for her.' },
      { beat: 'Crisis 3',         act: 2, prompt: 'What optional third crisis (or major backstory revelation) removes the last piece of context the audience needs?',                                              hint: 'This is optional — use it if your story has a piece of backstory that hasn\'t landed yet. It\'s the revelation that makes the climax\'s weight fully comprehensible.',                  placeholder: 'We learn her mother died of the same condition after refusing treatment. She chose her career over her life too.' },
      { beat: 'Climax',           act: 3, prompt: 'What is the single moment when every crisis converges — external and internal, present and past?',                                                               hint: 'The Fichtean climax should feel both surprising and completely inevitable. Every crisis was pointing here.',                                                                               placeholder: 'She\'s mid-surgery when her hand locks. She cannot finish. She calls for relief, steps back, removes her mask, and walks out.' },
      { beat: 'Resolution',       act: 3, prompt: 'What brief resolution follows — and what does the protagonist\'s changed state look like?',                                                                      hint: 'Keep it short. The work was done in the crises and the climax. The resolution simply confirms what changed.',                                                                              placeholder: 'Six months later: she is teaching surgical technique at a residency program. Right-handed. Seated. Excellent.' },
    ],
  },

  // ─── Kishōtenketsu ──────────────────────────────────────────────────────────
  'kishotenketsu': {
    displayName: 'Kishōtenketsu',
    tagline: 'Four-act structure — no conflict required',
    premise: [
      { id: 'element_a',   label: 'What is your first narrative element — the world, character, or situation you\'ll establish?',            hint: 'Ki introduces this element fully and without rushing. Give the audience time to settle into it.',                                              placeholder: 'An elderly woman who tends a small garden in a crowded Tokyo apartment block.' },
      { id: 'element_b',   label: 'What is your second narrative element — seemingly unrelated to the first?',                              hint: 'Shō develops this second thread independently. The audience should have no clear sense of how they connect.',                                placeholder: 'A young delivery driver who takes a different route every day to avoid boredom.' },
      { id: 'connection',  label: 'What unexpected connection links these two elements in the Ten?',                                        hint: 'The Ten is a shift in perception, not a plot twist. The audience should feel: "of course" — not "I didn\'t see that coming."',             placeholder: 'The garden was planted by his grandmother. He has been delivering her medicine for a year without knowing.' },
      { id: 'resonance',   label: 'What emotional truth lands when the Ketsu reconciles both elements?',                                    hint: 'Kishōtenketsu doesn\'t explain its meaning. It trusts the resonance to do the work. What feeling is the reader left with?',              placeholder: 'That connection exists everywhere, quietly, under the surface of daily life — whether or not we notice it.' },
    ],
    beats: [
      { beat: 'Ki',     act: 1, prompt: 'How do you establish your first element fully — world, character, atmosphere — without introducing conflict?',                                                            hint: 'Ki is pure immersion. No problem. No tension. Just existence. Let the audience settle into this world before it expands.',                                                                 placeholder: 'We follow her through the full morning routine: watering, pruning, naming each plant. The block watches without watching.' },
      { beat: 'Shō',    act: 1, prompt: 'How do you introduce and develop a second element that seems entirely separate from the first?',                                                                          hint: 'Shō does not explain the connection. It develops the second element with the same care as Ki. Patience here is craft.',                                                                     placeholder: 'We follow him through a full shift: fifteen deliveries, fifteen routes, fifteen small detours into streets he\'s never seen.' },
      { beat: 'Ten',    act: 2, prompt: 'What unexpected connection or shift in perspective links the two elements — changing how the audience sees both?',                                                         hint: 'The Ten is not a plot twist. It is a reframing. The audience should not be shocked — they should feel a quiet recognition, as if they always knew.',                                       placeholder: 'He parks outside the block, checks his manifest, finds her name. He\'s delivered here 247 times.' },
      { beat: 'Ketsu',  act: 3, prompt: 'How do both elements reconcile into a resonant whole — without explaining what it means?',                                                                                hint: 'Ketsu does not explain. It trusts the audience. Show the reconciliation and close. The meaning is theirs to keep.',                                                                         placeholder: 'She tends the garden. He delivers the package. He rings the bell. She answers. They recognize each other from the window.' },
    ],
  },

  // ─── Seven-Point Story Structure ────────────────────────────────────────────
  'seven-point-story': {
    displayName: "Dan Wells' Seven-Point Structure",
    tagline: 'Build from the ending backward',
    premise: [
      { id: 'resolution',  label: 'What is your resolution — who is your protagonist at the end?',    hint: 'Write the ending first. The Seven-Point system works backward. Know who they become.',                   placeholder: 'She is a detective who trusts her instincts over procedure — and leads a team that does the same.' },
      { id: 'hook',        label: 'What is your hook — who is your protagonist at the beginning, the mirror opposite of the resolution?', hint: 'The Hook is the polar opposite of the Resolution. If the Resolution is "trusts instincts," the Hook is "trusts procedure over everything."', placeholder: 'She is a by-the-book investigator who has never filed a single deviation from protocol in twelve years.' },
      { id: 'antagonist',  label: 'What is the antagonistic force — person, system, or internal resistance — that creates both Pinch Points?', hint: 'The antagonist demonstrates its power at both Pinch Points. Name it clearly.',                         placeholder: 'A serial offender who operates in the gaps between jurisdictions — precisely where procedure fails.' },
      { id: 'midshift',    label: 'What shift at the Midpoint moves the protagonist from reaction to action?',                             hint: 'Before the Midpoint, the protagonist reacts. After it, they act. Name the specific shift.',                placeholder: 'She stops waiting for permission and begins working the case on her own time.' },
    ],
    beats: [
      { beat: 'Hook',          act: 1, prompt: 'What is the starting state — the mirror opposite of your ending? Show who the protagonist is before they change.',                                                      hint: 'The Hook must be clearly opposite to the Resolution. If the change is "learns to feel," show someone who doesn\'t.',                                                                       placeholder: 'She processes a crime scene by checklist, alone, with noise-cancelling headphones and no small talk.' },
      { beat: 'Plot Turn 1',   act: 1, prompt: 'What event propels the protagonist into the main conflict — and forces them into unfamiliar territory?',                                                               hint: 'Plot Turn 1 moves the protagonist from the Hook world into the story\'s central struggle. It\'s an inciting event, not a decision — though it requires one.',                              placeholder: 'She\'s assigned a case that connects a string of deaths her department treated as accidents. She doesn\'t believe it.' },
      { beat: 'Pinch Point 1', act: 2, prompt: 'How does the antagonist demonstrate its power and put real pressure on the protagonist\'s progress?',                                                                  hint: 'A Pinch Point is the antagonist in full force. It should remind the audience (and the protagonist) what they are up against. Not a setback — a demonstration.',                          placeholder: 'A witness she\'d been cultivating is killed within 24 hours of contact. She had followed every protocol. It didn\'t matter.' },
      { beat: 'Midpoint',      act: 2, prompt: 'What moment shifts the protagonist from reacting to actively driving events?',                                                                                         hint: 'Before the Midpoint: the story happens to them. After: they happen to the story. This is the pivot. It may be a decision, a revelation, or a loss.',                                      placeholder: 'She realizes the offender has a source inside the department. She stops filing reports. She starts working her own network.' },
      { beat: 'Pinch Point 2', act: 2, prompt: 'How does the antagonist escalate — demonstrating even greater power, specifically targeting what the protagonist has built?',                                           hint: 'Pinch Point 2 is worse than Pinch Point 1. The antagonist is now targeting the protagonist\'s new approach. The walls close in.',                                                          placeholder: 'Her partner is suspended on fabricated charges. She is alone and running out of time.' },
      { beat: 'Plot Turn 2',   act: 3, prompt: 'What final piece of information or insight enables the Resolution?',                                                                                                   hint: 'Plot Turn 2 gives the protagonist what they need to win. It may come from within (a realization) or without (a key piece of evidence). It enables the Finale.',                          placeholder: 'Her partner, suspended but free, has been working the same thread. They meet off the books. He has what she needed.' },
      { beat: 'Resolution',    act: 3, prompt: 'How does the protagonist achieve the state that is the mirror opposite of the Hook?',                                                                                  hint: 'The Resolution proves the transformation. Show the protagonist doing something that was impossible at the Hook.',                                                                          placeholder: 'She makes the arrest with no authorization, in front of her chief, without hesitation, using only what she felt was right.' },
    ],
  },

  // ─── Freytag's Pyramid ──────────────────────────────────────────────────────
  'freytags-pyramid': {
    displayName: "Freytag's Pyramid",
    tagline: '5-stage arc — diagnose structure or build classical drama',
    premise: [
      { id: 'protagonist',  label: 'Who is the protagonist and what is their fatal flaw or fatal circumstance?',    hint: 'Freytag\'s Pyramid was built for tragedy. The protagonist carries within them the seed of their own undoing.',       placeholder: 'A general whose loyalty to his king exceeds his loyalty to truth — and who doesn\'t know it yet.' },
      { id: 'inciting',     label: 'What inciting event sets the Rising Action in motion?',                         hint: 'The inciting event disrupts equilibrium and makes the Climax inevitable.',                                             placeholder: 'He is asked to suppress evidence of a massacre his king ordered. He does it without question.' },
      { id: 'climax',       label: 'What is the Climax — the moment of highest tension, where the fate of the protagonist is determined?', hint: 'In Freytag\'s model, the Climax is the turning point. After this, the direction of the story changes irreversibly.', placeholder: 'The king orders him to execute an innocent man using the evidence he suppressed. He cannot do it. He cannot stop it.' },
      { id: 'resolution',   label: 'What does the Denouement reveal about what the story meant?',                  hint: 'The Denouement is not just aftermath. It holds the story\'s meaning — the cost, the lesson, the echo.',                 placeholder: 'He survives. The innocent man\'s daughter forgives him. The general lives with having been good enough to feel it, not brave enough to stop it.' },
    ],
    beats: [
      { beat: 'Exposition',     act: 1, prompt: 'How do you establish the world, the protagonist, and the stable order that will be disrupted?',                                                                      hint: 'The Exposition sets the baseline. What does normal look like — and what is the fault line running through it?',                                                                           placeholder: 'The army is victorious. The general is celebrated. He lives by a code that has always worked — until now.' },
      { beat: 'Rising Action',  act: 2, prompt: 'What sequence of events escalates the central conflict toward the Climax — each one raising the stakes?',                                                             hint: 'Rising Action is not one event. It is a series of increasingly urgent complications, each one closing off escape routes.',                                                                 placeholder: 'He suppresses one piece of evidence. Then a second. Then a witness must be silenced. He keeps going. The mountain grows.' },
      { beat: 'Climax',         act: 2, prompt: 'What is the single turning point — the moment of maximum tension from which the story cannot return?',                                                                hint: 'Everything before this was preparation. Everything after is consequence. Identify the exact moment the balance tips.',                                                                     placeholder: 'He is handed the execution order. His signature is the last thing between the order and the death.' },
      { beat: 'Falling Action', act: 3, prompt: 'How do the consequences of the Climax unfold — and what is the final attempt to escape or reconcile what happened?',                                                   hint: 'Falling Action moves toward the Denouement but is not there yet. Loose threads pull taut. The protagonist may still act — but within the logic of what has already been decided.',        placeholder: 'He testifies under oath. Partial truth. He condemns himself to half-life: free in body, imprisoned in everything else.' },
      { beat: 'Denouement',     act: 3, prompt: 'How does the story come to rest — and what meaning settles over the events?',                                                                                         hint: 'The Denouement is the last breath of the story. Not just what happens — what it means. What the audience carries out with them.',                                                          placeholder: 'He visits the man\'s grave every year. Alone. Without telling anyone. The general who won every battle.' },
    ],
  },

  // ─── Snowflake Method ───────────────────────────────────────────────────────
  'snowflake-method': {
    displayName: 'Snowflake Method',
    tagline: 'Design outward from one sentence — for novelists',
    premise: [
      { id: 'sentence',     label: 'Write your one-sentence summary (25 words or fewer).',          hint: 'No character names. No subplots. One protagonist, one central conflict, one stakes.',                          placeholder: 'A forensic accountant must expose her father\'s killers using the very financial tools they built to silence him.' },
      { id: 'protagonist',  label: 'Who is the protagonist and what do they want versus what do they need?', hint: 'Separate the external want (plot) from the internal need (theme). The gap between them IS the character arc.', placeholder: 'She wants justice. She needs to accept that justice and closure are not the same thing.' },
      { id: 'antagonist',   label: 'Who or what is the antagonist — and what is their motivation?',  hint: 'In the Snowflake, the antagonist has their own internal logic. They are not wrong in their own story.',         placeholder: 'A financial architect who believes systems require human sacrifice to function. He\'s been right for twenty years.' },
      { id: 'theme',        label: 'In one sentence: what is this novel about thematically?',        hint: 'Not plot — theme. What truth does this novel explore?',                                                         placeholder: 'Systems designed to protect the powerful are only vulnerable to those willing to become dangerous.' },
    ],
    beats: [
      { beat: 'Step 1: One-sentence summary',   act: 1, prompt: 'Refine your one-sentence summary until it captures protagonist, conflict, and stakes in 25 words or fewer.',                                            hint: 'Test it: does it exclude subplots? Does it name only the most essential conflict? Could someone explain your book with this sentence?',                                                     placeholder: 'A forensic accountant exposes her father\'s killers using the financial architecture they built to destroy all evidence.' },
      { beat: 'Step 2: One-paragraph (5 sentences)', act: 1, prompt: 'Expand to five sentences: setup, three disasters, and ending.',                                                                                    hint: 'Sentence 1: setup. Sentence 2: first disaster. Sentence 3: second disaster. Sentence 4: third disaster (the climax). Sentence 5: ending. No more.',                                        placeholder: 'She inherits nothing from her father except a discrepancy in a line item. Sentence 2: She is warned off. Sentence 3: Her ally is killed...' },
      { beat: 'Step 3: Character summaries',    act: 1, prompt: 'Write one paragraph for each major character: their name, storyline, motivation, goal, and arc.',                                                       hint: 'Focus on change. Who are they at the beginning and who are they at the end? The story only works if multiple characters transform.',                                                        placeholder: 'PROTAGONIST: She begins as someone who believes systems can be fixed from inside. She ends as someone who knows they must be broken first.' },
      { beat: 'Step 4: Expanded synopsis',      act: 2, prompt: 'Expand each sentence of your paragraph into a full page. You now have a five-page synopsis.',                                                           hint: 'Each page covers one major section. Write in paragraph form. You are designing the novel — not drafting it.',                                                                               placeholder: 'Act 1 page: Full setup of her father\'s estate, her background, the specific discrepancy she finds, and the first warning.' },
      { beat: 'Step 5: Scene list',             act: 2, prompt: 'Expand the synopsis into a scene-by-scene list. Each scene: whose POV, what happens, how it moves the story.',                                          hint: 'For each scene, note: POV character, conflict, outcome. If a scene has no conflict and moves nothing forward — cut it before you write it.',                                               placeholder: 'Scene 1: Her POV. Estate sale. She finds the discrepancy in her father\'s last signed audit. She keeps it, says nothing. Moves story: seeds the central mystery.' },
      { beat: 'Step 6: Draft',                  act: 3, prompt: 'With your scene list as your guide — begin. What does the first page look like?',                                                                        hint: 'The Snowflake exists so that when you write, you already know what every scene is doing. Write with confidence. You\'ve already solved the structure.',                                     placeholder: 'She wore her father\'s reading glasses to the estate sale. She told herself it was because hers were in the car.' },
    ],
  },

  // ─── Hauge's Six-Stage Structure ────────────────────────────────────────────
  'hauge-six-stage': {
    displayName: "Hauge's Six-Stage Structure",
    tagline: 'Map outer journey against inner transformation',
    premise: [
      { id: 'identity',     label: 'What is the protagonist\'s Identity — the false self they protect at the start?',       hint: 'The Identity is the mask. It\'s who the protagonist pretends to be (or believes themselves to be) to avoid their deepest wound.',            placeholder: 'She is "the reliable one" — the person who shows up, fixes things, and never asks for help. It\'s armor, not character.' },
      { id: 'essence',      label: 'What is the protagonist\'s Essence — who they truly are beneath the Identity?',         hint: 'The Essence is who emerges when the Identity can no longer hold. The story is the pressure that forces that emergence.',                   placeholder: 'Beneath the reliability is someone who is terrified of being truly seen — and desperate for it.' },
      { id: 'outer_want',   label: 'What is the outer motivation — the concrete goal the plot is built around?',             hint: 'The outer want drives Act 1. It\'s what the protagonist says they need. Name it specifically.',                                               placeholder: 'She wants to win custody of her younger siblings after their parents\' death.' },
      { id: 'inner_journey',label: 'What does the inner journey require the protagonist to surrender?',                      hint: 'Hauge\'s central question: what must the protagonist give up to move from Identity toward Essence?',                                          placeholder: 'She must give up the idea that being needed is the same as being loved.' },
    ],
    beats: [
      { beat: 'Stage 1: Setup',          act: 1, prompt: 'How do you establish the protagonist\'s Identity — who they pretend or believe themselves to be? (0–10%)',                                                     hint: 'Show the Identity in action. The protagonist is competent, functional, and defended. The Essence is entirely invisible.',                                                                   placeholder: 'She runs her siblings\' lives like a project manager: schedules, plans, no deviation. She hasn\'t cried since the accident.' },
      { beat: 'Stage 2: New Situation',  act: 1, prompt: 'What new situation forces the protagonist into unfamiliar territory — and begins cracking the Identity? (10–25%)',                                              hint: 'The New Situation puts the Identity to the test in a context where its usual tools don\'t fully work. Small cracks appear.',                                                               placeholder: 'The custody hearing reveals that what the court wants is not what she\'s been providing. She needs to show feeling. She can\'t.' },
      { beat: 'Stage 3: Progress',       act: 2, prompt: 'How does the protagonist pursue their outer goal — and what small movements toward Essence occur in the process? (25–50%)',                                      hint: 'Stage 3 is the upside of Act 2. Progress is real but partial. The outer goal advances while the inner transformation begins, unacknowledged.',                                            placeholder: 'She takes a parenting class she doesn\'t need. She lets her youngest sibling sleep in her bed for the first time.' },
      { beat: 'Stage 4: Complications',  act: 2, prompt: 'What complications make both the outer goal and the inner transformation harder — and force deeper sacrifice? (50–75%)',                                         hint: 'The Identity reasserts itself. The protagonist retreats. The wound is touched and the armor goes back up, at cost.',                                                                         placeholder: 'A welfare worker recommends against her. She fires back with documentation and loses the room. She can\'t stop protecting herself.' },
      { beat: 'Stage 5: Final Push',     act: 3, prompt: 'What is the final push toward the outer goal — and how does it require the protagonist to shed Identity and act from Essence? (75–90%)',                         hint: 'Stage 5 is the protagonist fully committing — not to the outer goal alone, but to becoming who they actually are. The Identity is released here.',                                        placeholder: 'She shows up to the final hearing without her notes. She answers questions. She says: "I don\'t know. But I\'m not going anywhere."' },
      { beat: 'Stage 6: Aftermath',      act: 3, prompt: 'What is the new equilibrium — and how does it demonstrate that the protagonist is now living from Essence? (90–100%)',                                           hint: 'The Aftermath shows the new state. Not a return to normal — a new normal. The Identity is not gone, but it is no longer running things.',                                                  placeholder: 'She wins. She cries at the verdict. Her youngest sibling holds her hand. She doesn\'t apologize for it.' },
    ],
  },

  // ─── Heroine's Journey ──────────────────────────────────────────────────────
  'heroines-journey': {
    displayName: "Heroine's Journey",
    tagline: "Maureen Murdock's 10-stage feminine descent",
    premise: [
      { id: 'separation',   label: 'What has the heroine rejected about the feminine — and why?',         hint: 'The journey begins with separation. What cultural or personal wound made the "feminine world" feel insufficient or dangerous?',    placeholder: 'She left her mother\'s softness behind at fourteen and built herself in her father\'s image — driven, analytical, defended.' },
      { id: 'masculine',    label: 'What has she built in the masculine world — and what has it cost her?', hint: 'She has achieved. Name the achievement. Name the cost.',                                                                   placeholder: 'She runs the department. She hasn\'t spoken to her sister in six years. She doesn\'t think these are related.' },
      { id: 'descent',      label: 'What initiates the descent — the moment her masculine-identified success stops working?',  hint: 'The descent is not a defeat. It is an invitation downward into what was left behind.',                     placeholder: 'Her mother is dying. She goes home. Everything she managed not to feel is still there, exactly where she left it.' },
      { id: 'integration',  label: 'What would integration look like — not a choice between masculine and feminine, but a wholeness?', hint: 'The journey ends in integration, not replacement. Who is she when she carries both?',          placeholder: 'She leads the department and she calls her sister. She is ambitious and she is present. Both.' },
    ],
    beats: [
      { beat: 'Separation from the Feminine',          act: 1, prompt: 'How is the heroine\'s rejection of the feminine world established?',                                                                                hint: 'Show the split in action. Not narrated — embodied in behavior, relationship, choice.',                                                                                                     placeholder: 'She introduces herself by her title at her mother\'s church. She corrects people who call her by her first name.' },
      { beat: 'Identification with the Masculine',     act: 1, prompt: 'What is the masculine-identified achievement — the success that defines her public self?',                                                          hint: 'This is not a critique of ambition. It is an honest portrait of what was built and at what cost.',                                                                                         placeholder: 'Head of the division at 34. The youngest. She keeps the plaque in her office facing the door.' },
      { beat: 'Road of Trials',                        act: 2, prompt: 'What trials test the masculine-identified self — and reveal its limits?',                                                                           hint: 'The masculine-identified self is competent. What problems does competence fail to solve?',                                                                                                  placeholder: 'Her mother refuses the treatment plan she researched. Her mother wants her present, not efficient.' },
      { beat: 'Illusory Boon of Success',              act: 2, prompt: 'What apparent success reinforces the old strategy — just before it collapses?',                                                                      hint: 'The heroine believes the masculine approach has worked. It hasn\'t. The boon is real but insufficient.',                                                                                    placeholder: 'She negotiates better care for her mother — more specialists, better facility. Her mother cries and asks her to stay.' },
      { beat: 'Spiritual Aridity / Awakening',         act: 2, prompt: 'What moment of emptiness or crisis signals that the old strategy is no longer enough?',                                                             hint: 'Not a failure. An inner recognition. Something is missing. Name it specifically.',                                                                                                          placeholder: 'Her mother sleeps. She sits in the chair beside the bed. She doesn\'t know what to do with her hands. She has never not known what to do.' },
      { beat: 'Initiation and Descent to the Goddess', act: 2, prompt: 'What is the descent — the crossing into the deep interior, the encounter with what was buried?',                                                    hint: 'The Goddess is not a figure. She is the interior feminine — feeling, intuition, connection. The descent is frightening. It is also the only way forward.',                                 placeholder: 'Her mother asks her to wash her hair. She does it. She sits on the bathroom floor afterwards and cries for the first time in years.' },
      { beat: 'Urgent Yearning to Reconnect',          act: 3, prompt: 'What urgent desire to reconnect — with others, with herself — arises from the descent?',                                                            hint: 'The yearning comes from the descent. It is not manufactured. It is discovered.',                                                                                                            placeholder: 'She calls her sister at 2am. She doesn\'t have a plan for the conversation. She calls anyway.' },
      { beat: 'Healing the Mother/Daughter Split',     act: 3, prompt: 'What specific reconciliation — literal or internal — begins repairing the original separation?',                                                    hint: 'This may be a conversation, an action, or an internal shift. The split was real. The healing must be earned.',                                                                              placeholder: 'She tells her mother she is sorry for being absent. Her mother says she knew. That she waited. That she\'s glad she came.' },
      { beat: 'Healing the Wounded Masculine',         act: 3, prompt: 'How does the heroine reclaim the healthy masculine — ambition, agency, direction — without the wound?',                                             hint: 'The masculine is not the enemy. The wound is. Distinguish between the two. What does healthy ambition look like for her now?',                                                             placeholder: 'She goes back to work. She runs the division. She also has a standing call every Sunday.' },
      { beat: 'Integration of Feminine and Masculine', act: 3, prompt: 'What does wholeness look like in the final image?',                                                                                                 hint: 'Not balance. Integration. Both exist simultaneously in the same person.',                                                                                                                   placeholder: 'She chairs the board meeting. Her phone buzzes: her sister\'s daughter\'s first steps. She smiles, mid-sentence, and keeps going.' },
    ],
  },

  // ─── Story Spine ────────────────────────────────────────────────────────────
  'story-spine': {
    displayName: 'Story Spine',
    tagline: "Kenn Adams' 7-beat improv framework",
    premise: [
      { id: 'character',   label: 'Who is your protagonist and what is their ordinary world?',  hint: 'Story Spine is designed to move fast. Establish the protagonist simply and concretely.',    placeholder: 'A librarian who has organized the same collection for thirty years and knows exactly where everything is.' },
      { id: 'disruption',  label: 'What disrupts the ordinary?',                                hint: 'The "Until one day" beat is the engine. Name it clearly.',                                   placeholder: 'A water main bursts and destroys an entire wing — including the section she was never allowed to catalog.' },
      { id: 'consequence', label: 'What larger consequence does the disruption set in motion?',  hint: 'Story Spine escalates quickly. The "Because of that" beats compound. What is the domino effect?', placeholder: 'The destroyed wing turns out to hold documents the city has been hiding. And now they\'re visible.' },
    ],
    beats: [
      { beat: 'Once upon a time...',          act: 1, prompt: 'Establish your protagonist and their ordinary world. Who are they and what is stable?',                                                                         hint: 'Keep it simple. One character, one world, one established order. This is the before.',                                                                                                      placeholder: 'Once upon a time, there was a librarian who had not taken a day off since 1998, and who knew every book by feel.' },
      { beat: 'Every day...',                 act: 1, prompt: 'What is the rhythm of their ordinary existence — the routine that defines them?',                                                                                hint: '"Every day" establishes the repeating pattern. It makes the disruption feel like a break from something real.',                                                                             placeholder: 'Every day, she arrived at 7:47am, unlocked the east wing first, and made her rounds in the same order.' },
      { beat: 'Until one day...',             act: 1, prompt: 'What single event breaks the pattern and sets everything in motion?',                                                                                           hint: 'The "Until one day" is the inciting incident. It must break the "Every day" pattern specifically.',                                                                                         placeholder: 'Until one day, a water main burst overnight, and when she arrived at 7:47am the east wing was gone.' },
      { beat: 'Because of that...',           act: 2, prompt: 'What is the first direct consequence of the disruption?',                                                                                                       hint: 'Each "Because of that" must follow causally from the previous beat. No jumps. Escalation through logic.',                                                                                   placeholder: 'Because of that, she cataloged the damage and found documents in the rubble that weren\'t in any index.' },
      { beat: 'Because of that... (escalate)',act: 2, prompt: 'What larger consequence follows from the first?',                                                                                                               hint: 'This is the escalation beat. The consequences compound. The stakes rise specifically.',                                                                                                     placeholder: 'Because of that, the city council arrived with lawyers before the salvage crew and told her the documents were private.' },
      { beat: 'Until finally...',             act: 3, prompt: 'What is the climactic moment — the point at which the situation reaches its breaking point?',                                                                   hint: '"Until finally" is the crisis and the resolution beginning. It ends the escalation and turns toward closure.',                                                                              placeholder: 'Until finally, she photographed every page before handing them over, and mailed the images to a journalist she\'d once helped find a book.' },
      { beat: 'Ever since then...',           act: 3, prompt: 'What is the new ordinary — how has the world and the protagonist settled into a changed state?',                                                                 hint: '"Ever since then" is the Denouement. Not just aftermath — a new equilibrium. What is the "Every day" now?',                                                                                 placeholder: 'Ever since then, the east wing is a public archive. She still arrives at 7:47am, but she unlocks the records room first.' },
    ],
  },

  // ─── Five-Act Structure ─────────────────────────────────────────────────────
  'five-act': {
    displayName: 'Five-Act Structure',
    tagline: 'Classical dramatic structure — exposition through catastrophe',
    premise: [
      { id: 'protagonist',   label: 'Who is the protagonist and what is their fatal flaw or defining tension?',       hint: 'Five-Act structure, particularly in Shakespeare, builds around a protagonist whose nature contains the seed of the climax.',   placeholder: 'A king who confuses loyalty with love and cannot distinguish between the two.' },
      { id: 'inciting',      label: 'What inciting action in Act I sets the tragic or dramatic machinery in motion?', hint: 'The inciting action establishes the terms of the contract between the protagonist and their fate.',                          placeholder: 'He divides his kingdom between his daughters based on declarations of love — and disinherits the honest one.' },
      { id: 'turn',          label: 'What is the central turn in Act III — the point of no return?',                  hint: 'Act III is the hinge. After this, the direction of the play inverts and the falling action begins.',                         placeholder: 'He realizes his loyal daughter was the one he cast out — at the moment he is cast out himself.' },
      { id: 'catastrophe',   label: 'What is the catastrophe — the event that confirms the play\'s meaning?',         hint: 'In tragedy, the catastrophe is the final cost. In drama, it may be transformation or revelation. What is yours?',          placeholder: 'He holds his dead daughter and understands, too late, what love actually was.' },
    ],
    beats: [
      { beat: 'Act I — Exposition',             act: 1, prompt: 'How do you establish the world, the protagonist, and the initial situation — including the fault line that will eventually fracture everything?',           hint: 'The Exposition establishes two things: the protagonist\'s power (what they have to lose) and their flaw (what will cost them it).',                                                          placeholder: 'A king at the height of his power. His court arranged around him. His daughters present. His mistake about to happen.' },
      { beat: 'Act II — Rising Action',         act: 2, prompt: 'What series of events escalates the central conflict — each one increasing pressure and closing escape routes?',                                             hint: 'Rising Action is not one event. It is a staircase. Each step makes the Climax more inevitable.',                                                                                           placeholder: 'He is humiliated by his daughters. He is stripped of his retinue. He is turned out into the storm. The map of his mistake unfolds.' },
      { beat: 'Act III — Climax / Turn',        act: 3, prompt: 'What is the moment of maximum dramatic tension — the point where the play\'s direction reverses?',                                                           hint: 'In a five-act structure, this is the exact center. The protagonist confronts something that cannot be unchanged. The play turns here.',                                                      placeholder: 'On the heath, in the storm, he understands what he has done. Not what was done to him — what he did. The recognition is the catastrophe.' },
      { beat: 'Act IV — Falling Action',        act: 4, prompt: 'How do the consequences of the Climax unfold — and what final attempt to recover or reconcile happens here?',                                                hint: 'Falling Action moves toward the resolution but is not yet there. Characters react, attempt last maneuvers, and some threads close before the end.',                                        placeholder: 'His loyal allies try to restore him. His enemies overreach. The loyal daughter returns with an army. It is almost not too late.' },
      { beat: 'Act V — Catastrophe or Denouement', act: 5, prompt: 'What is the catastrophe or resolution — and what does it confirm about what the play has been about?',                                                    hint: 'In tragedy, the catastrophe reveals the full cost of the flaw. In comedy or drama, the Denouement resolves the action into a new order. Either way, it must feel inevitable.',             placeholder: 'The loyal daughter is killed before he can reach her. He holds her. The kingdom\'s new rulers look on. The play ends.' },
    ],
  },

  // ─── Romancing the Beat ─────────────────────────────────────────────────────
  'romancing-the-beat': {
    displayName: 'Romancing the Beat',
    tagline: "Gwen Hayes' 13-beat romance structure",
    premise: [
      { id: 'protagonist_a', label: 'Who is your first lead — and what wound or misbelief makes love feel dangerous to them?',  hint: 'In romance structure, the internal wound is what makes the HEA (happily ever after) feel genuinely earned.',             placeholder: 'She believes she is fundamentally unlovable — not in a self-pitying way, but as a settled fact she\'s arranged her life around.' },
      { id: 'protagonist_b', label: 'Who is your second lead — and what wound or misbelief mirrors or complements the first?',  hint: 'The two misbeliefs should create friction and also, ultimately, resolution. They must need each other to heal.',         placeholder: 'He believes love requires him to disappear — to make himself small enough not to be rejected before he gets there first.' },
      { id: 'external',      label: 'What external circumstance forces these two into proximity?',                               hint: 'Romance requires proximity. What situation keeps them close long enough for the emotional stakes to develop?',            placeholder: 'They are co-assigned to plan their shared friend group\'s annual event — from opposite sides of the country, virtually, for six weeks.' },
      { id: 'hea',           label: 'What does the HEA (happily ever after) or HFN (happy for now) look like specifically?',    hint: 'Name the ending concretely. The whole structure builds toward it.',                                                         placeholder: 'She tells him she loves him and means it with her whole body. He says it back without shrinking. They are both fully present.' },
    ],
    beats: [
      { beat: 'The Meet',              act: 1, prompt: 'How do the two leads meet — and what is the immediate, specific quality each notices in the other?',                                                                    hint: 'The Meet establishes the charge. There should be attraction and friction simultaneously.',                                                                                                  placeholder: 'She notices he is the only person in the video call who looks genuinely annoyed to be there. She finds it interesting.' },
      { beat: 'Wanting',               act: 1, prompt: 'What is the first honest moment of wanting — the acknowledgment, however resisted, that something is there?',                                                           hint: 'Wanting is the admission the plot is pretending to avoid. It happens early and gets buried — but the audience sees it.',                                                                   placeholder: 'He watches her explain a seating chart with the same precision she clearly uses to explain everything, and thinks: that is the most attractive thing I\'ve ever seen.' },
      { beat: 'Misbeliefs & Wounds',   act: 1, prompt: 'What internal misbelief does each character carry — and how is it made visible early in the story?',                                                                   hint: 'The misbelief doesn\'t have to be stated. Show it in a behavior, a refusal, a deflection.',                                                                                                placeholder: 'She deflects every compliment. He always finds a reason to make himself useful rather than simply present.' },
      { beat: 'No Way This Is Going Anywhere', act: 1, prompt: 'What external or internal reason makes both characters decide this is not happening — even as it already is?',                                                  hint: 'This is the conscious denial that the audience knows is already failing.',                                                                                                                  placeholder: 'They live on different coasts. This is a work relationship. She doesn\'t do this.' },
      { beat: 'Humming Along',         act: 2, prompt: 'What period of growing closeness, collaboration, and unacknowledged intimacy develops before the complications arrive?',                                                 hint: '"Humming Along" is the story working. Things are good. Both characters are letting their guard down in small ways.',                                                                        placeholder: 'They start their planning calls early. They stay late. They send each other things that have nothing to do with the event.' },
      { beat: 'Shiny Hoo-Ha Moment',   act: 2, prompt: 'What moment of peak connection — physical, emotional, or both — promises everything?',                                                                                  hint: 'This is the "false summit." It feels like the HEA arriving early. It\'s actually the moment that makes the Dark Moment hit harder.',                                                       placeholder: 'They meet in person for the first time at a site visit. She laughs at something he says. He touches her arm. Neither of them moves away.' },
      { beat: 'Resonance',             act: 2, prompt: 'What moment of genuine emotional resonance — not attraction, but recognition — deepens the connection?',                                                                hint: 'Resonance is when two people see each other clearly, not romantically. A specific, quiet moment of true recognition.',                                                                     placeholder: 'He sees her still at her computer at midnight and says nothing — just sends her coffee to the hotel concierge with a note: "For the person who cares too much."' },
      { beat: 'The Swoon',             act: 2, prompt: 'What is the moment of maximum romantic escalation — the point at which both characters are fully, undeniably in it?',                                                   hint: 'The Swoon is what romance readers came for. Make it specific. Make it earned.',                                                                                                             placeholder: 'He tells her he booked a flight change to have three more hours in the city. She doesn\'t say anything. She takes his hand.' },
      { beat: 'Deepening',             act: 2, prompt: 'What vulnerability is shared — the moment one or both characters reveal something they don\'t usually show?',                                                           hint: 'Deepening comes after the Swoon. The walls are lower. Something true is offered.',                                                                                                          placeholder: 'She tells him about her mother, who left when she was nine, and why she makes lists — because lists stay.' },
      { beat: 'Commitment Freakout',   act: 2, prompt: 'What moment of panic causes one or both characters to pull back from what\'s developing?',                                                                              hint: 'The Freakout is the misbelief resurfacing at the exact worst moment.',                                                                                                                      placeholder: 'He sends her a gift that is very specific to her. She realizes he has been paying attention in ways she hasn\'t been letting herself acknowledge. She doesn\'t respond for three days.' },
      { beat: 'The Dark Moment',       act: 3, prompt: 'What causes the central relationship to fall apart — the crisis that seems to confirm both characters\' worst fears?',                                                   hint: 'The Dark Moment must arise from the misbeliefs, not from external plot. It should feel like both characters are exactly as broken as they feared.',                                         placeholder: 'He assumes her silence means she has made her decision. He accepts the job offer that takes him to a third city. He doesn\'t tell her.' },
      { beat: 'Groveling / Grand Gesture', act: 3, prompt: 'How does one or both characters make it right — specifically, in a way that proves they have moved past their misbelief?',                                          hint: 'The gesture must cost something. It must demonstrate transformation, not just feeling.',                                                                                                     placeholder: 'She drives six hours to tell him in person that she is not someone who stays quiet when she wants something, and she has been practicing being that person for him.' },
      { beat: 'Happily Ever After',    act: 3, prompt: 'What is the final moment of the romance — the evidence that the HEA is real and specifically earned by these two?',                                                     hint: 'The HEA must reflect the specific misbeliefs that were healed. If she believed she was unlovable — show someone loving her fully and her receiving it.',                                    placeholder: 'He doesn\'t make himself small. She doesn\'t build a wall. They stand fully in it, in front of everyone, without bracing.' },
    ],
  },

  // ─── Virgin's Promise ───────────────────────────────────────────────────────
  'virgins-promise': {
    displayName: "The Virgin's Promise",
    tagline: "Kim Hudson's 13-stage transformation arc",
    premise: [
      { id: 'dependent',    label: 'What is the Dependent World — the world that defines the Virgin and limits her potential?',  hint: 'The Dependent World is not always bad. It may be loving. But it requires the Virgin to be less than she is.',            placeholder: 'A high-achieving daughter in a conservative family whose love is conditional on her conformity.' },
      { id: 'dream',        label: 'What is the Virgin\'s dream — the potential she is hiding, suppressing, or just beginning to discover?', hint: 'The dream must be specific. Not "freedom" — what specific expression of self does she long for?',             placeholder: 'She wants to make music. Not perform — compose. In private. Alone. She hasn\'t told anyone.' },
      { id: 'price',        label: 'What is the Price of Conformity — what the Virgin loses if she never pursues the dream?',    hint: 'The Price of Conformity is the cost of staying. Name it.',                                                              placeholder: 'She marries someone appropriate and becomes competent and invisible and fine.' },
      { id: 'shine',        label: 'What does it look like when the Virgin fully shines — and why does it threaten the Dependent World?', hint: 'Fully shining is not just personal triumph. It disrupts the world around her.',                              placeholder: 'She premieres a piece she wrote. The family is in the audience. They don\'t know the music is hers. When they learn, everything changes.' },
    ],
    beats: [
      { beat: 'Dependent World',           act: 1, prompt: 'What is the world that defines and constrains the Virgin — and what does she give up to exist within it?',                                                          hint: 'The Dependent World may be safe and loving. Show both the love and the constriction.',                                                                                                     placeholder: 'Her family is close and warm and proud of her. They also have a plan for her. The plan is detailed.' },
      { beat: 'Price of Conformity',       act: 1, prompt: 'What specific cost does the Virgin pay to remain acceptable in the Dependent World?',                                                                                hint: 'Show the price in behavior, not statement. What does she suppress, hide, or not say?',                                                                                                     placeholder: 'She auditioned for the conservatory application form, then didn\'t submit it. She still has the form.' },
      { beat: 'Opportunity to Shine',      act: 1, prompt: 'What opportunity appears that allows the Virgin to glimpse what her full potential feels like?',                                                                      hint: 'The Opportunity may be small. It is enough to ignite something.',                                                                                                                           placeholder: 'A visiting composer uses the family\'s old piano. He leaves his notebook open. She reads it and plays what she imagines he intended.' },
      { beat: 'Dresses the Part',          act: 1, prompt: 'How does the Virgin begin to try on the identity of who she could be — tentatively, in private or semi-private?',                                                    hint: '"Dressing the Part" is not public. It is a rehearsal of self.',                                                                                                                             placeholder: 'She rents a studio room by the hour with tutoring money. She tells no one. She goes every Tuesday.' },
      { beat: 'Secret World',              act: 2, prompt: 'Where does the Virgin build and inhabit a Secret World where she can fully be herself?',                                                                              hint: 'The Secret World is essential. It is where the dream has space to develop before it can face the light.',                                                                                   placeholder: 'The Tuesday studio becomes the only place where nothing is required of her. She begins finishing pieces.' },
      { beat: 'No Longer Fitting In',      act: 2, prompt: 'Where does the double life create friction — where does the Secret World begin to leak into the Dependent World?',                                                   hint: 'No Longer Fitting In is not a dramatic confrontation yet. It is a growing gap between who she is becoming and who the world expects.',                                                      placeholder: 'Her fiancé notices she\'s distracted. Her mother comments she seems far away. She is. She\'s composing in her head at dinner.' },
      { beat: 'Mentor Appears',            act: 2, prompt: 'Who appears to support and guide the Virgin\'s potential — not to rescue her, but to believe in her?',                                                               hint: 'The Mentor does not solve the problem. They witness and affirm.',                                                                                                                            placeholder: 'The visiting composer returns. He hears her through the studio wall. He asks who composed what she\'s playing.' },
      { beat: 'Fully Shines',              act: 2, prompt: 'What is the moment the Virgin fully expresses her potential — and sees herself as she truly is?',                                                                     hint: '"Fully Shines" is the zenith of the Secret World. She is complete. The world has not seen it yet.',                                                                                         placeholder: 'She performs her own piece for the composer alone. She doesn\'t apologize before she starts. She plays it all the way through.' },
      { beat: 'Kingdom in Chaos',          act: 3, prompt: 'How does the Secret World\'s existence destabilize the Dependent World — and how does the world react?',                                                              hint: 'The Kingdom in Chaos is not punishment. It is the natural disruption of the old order when truth enters it.',                                                                               placeholder: 'Her family discovers the studio rental receipts. Her fiancé finds the notebook. The plan is in chaos.' },
      { beat: 'Wanders in the Wilderness', act: 3, prompt: 'How does the Virgin navigate the collapse of both worlds — the Secret and the Dependent — without a clear path forward?',                                             hint: 'Wandering is not failure. It is the necessary space between the old world and the new one.',                                                                                                 placeholder: 'She cancels the Tuesday sessions. She also doesn\'t attend the engagement dinner. She does not know what she is yet.' },
      { beat: 'Choice to be Taken or Reclaimed', act: 3, prompt: 'What moment forces the Virgin to choose between the Dependent World\'s terms and her own fully shining self?',                                                  hint: 'This is the central crisis. The choice must be genuinely costly. Both options have real weight.',                                                                                           placeholder: 'The engagement ultimatum arrives the same day as the conservatory\'s late admission offer.' },
      { beat: 'The Kingdom is Brighter',   act: 3, prompt: 'How does the Virgin\'s choice and full shining ultimately enrich the world she came from — even if some of it falls away?',                                          hint: 'The Kingdom is Brighter because she chose herself. This is not punishment of the old world. It is transformation.',                                                                        placeholder: 'The premiere is small. Her mother is there. Not her father, not yet. Her mother cries. She doesn\'t explain to her mother. She plays it again.' },
      { beat: 'Rescue of the Prince',      act: 3, prompt: 'How does the Virgin\'s transformation free or liberate someone else — the "Prince" who was imprisoned in the old order too?',                                        hint: 'The Prince may be a romantic partner, a sibling, a parent. The Virgin\'s transformation gives someone else permission to change too.',                                                      placeholder: 'Her fiancé writes to say he had been performing the plan too. He wasn\'t sure he wanted it either. He thanks her.' },
    ],
  },

  // ─── MICE Quotient ──────────────────────────────────────────────────────────
  'mice-quotient': {
    displayName: 'MICE Quotient',
    tagline: "Orson Scott Card's nested story type framework",
    premise: [
      { id: 'dominant',    label: 'What is the dominant story type: Milieu, Idea, Character, or Event?',       hint: 'M = journey through a world. I = a question posed and answered. C = a character who must change. E = a disruption of order. Which drives your story?', placeholder: 'Character — this story is fundamentally about who my protagonist becomes.' },
      { id: 'opening',     label: 'How does your story open its dominant thread?',                               hint: 'Each story type opens in a specific way. Character: we see who they are. Milieu: they enter the world. Idea: the question is posed. Event: the disruption begins.', placeholder: 'We meet her at the moment she makes the choice that defines who she\'s been — so we understand who she was before she changes.' },
      { id: 'nesting',     label: 'What secondary story types are nested inside the dominant one?',              hint: 'Most stories have nested types. Name them. The rule: open each nested thread before the outer thread closes it.',                                       placeholder: 'Nested inside the Character story: an Idea thread (the mystery of her father\'s past) and a Milieu thread (she\'s trapped in a country she doesn\'t know).' },
      { id: 'closing',     label: 'In what order will the nested threads close — and what closes last?',         hint: 'Threads close in reverse order from how they opened. The dominant type closes last.',                                                                  placeholder: 'The Milieu thread closes when she escapes the country. The Idea thread closes when the mystery is resolved. The Character thread closes last: when she becomes who she needed to become.' },
    ],
    beats: [
      { beat: 'Identify dominant story type (M/I/C/E)', act: 1, prompt: 'Which of the four types dominates this story — and what is the specific contract it makes with the reader?',                                          hint: 'Milieu: enter a world, explore it, leave or stay. Idea: pose a question, investigate, answer it. Character: show who they are, force the change, show who they become. Event: establish order, disrupt it, restore or accept new order.',                   placeholder: 'This is a Character story. The contract: the audience will watch this person become someone fundamentally different.' },
      { beat: 'Milieu — Enter, explore, leave or stay',  act: 1, prompt: 'If Milieu is present: when does your protagonist enter the Milieu thread — and what does the world require of them?',                                hint: 'Milieu opens when the protagonist enters an unfamiliar world. It closes when they leave or choose to stay permanently.',                                                                     placeholder: 'She crosses into a country she\'s been running from for six years. The thread opens with the border crossing.' },
      { beat: 'Inquiry — Pose the question, investigate, answer', act: 1, prompt: 'If Idea is present: what question is posed — and when will it be answered?',                                                               hint: 'Idea opens with a question. It closes with the answer. Everything in between is the investigation.',                                                                                        placeholder: 'The question: did her father defect willingly, or was he forced? The investigation: every scene that moves toward the truth.' },
      { beat: 'Character — Show who they are, force the change, show who they become', act: 2, prompt: 'If Character is present: who is the protagonist before the change — and what forces the change upon them?',            hint: 'Character opens with identity and closes with transformation. The change must be forced by the story, not chosen painlessly.',                                                              placeholder: 'Before: someone who runs from connection. The change: she cannot solve this problem alone. Forced contact. Then: someone who stays.' },
      { beat: 'Event — Establish order, disrupt, restore or accept new order', act: 2, prompt: 'If Event is present: what order is disrupted — and what new order will be accepted or restored at the end?',                   hint: 'Event opens with an established order and closes when a new equilibrium is reached. The disruption in the middle is the engine.',                                                           placeholder: 'The order: the cartel controls the regional government. The disruption: her investigation. The new order: not restored — permanently changed.' },
      { beat: 'Nest additional types inside the dominant frame', act: 2, prompt: 'How are secondary story types nested inside the dominant one — and are they all properly opened before any of them close?',                   hint: 'Every nested thread must open before any thread closes. Closing out of order produces a structural collapse.',                                                                              placeholder: 'The Idea thread (her father\'s question) opens in Act 1. The Milieu thread (her entrapment) opens in Act 1. Both close before the Character thread closes in Act 3.' },
      { beat: 'Open each nested type; close before the outer type closes', act: 3, prompt: 'Are all nested threads closed before the dominant thread closes? Trace each one to its resolution.',                                 hint: 'This is a structural audit. Walk each thread to its close. The dominant thread closes last.',                                                                                               placeholder: 'Milieu closes: she escapes in Act 3, scene 2. Idea closes: she learns the truth in Act 3, scene 4. Character closes: she chooses to stay and build in Act 3, final scene.' },
    ],
  },

  // ─── W-Plot ─────────────────────────────────────────────────────────────────
  'w-plot': {
    displayName: 'W-Plot',
    tagline: 'Dual track — plot and emotional arc in parallel',
    premise: [
      { id: 'plot_track',     label: 'What is the external plot track — the outer goal and conflict?',          hint: 'The W-Plot runs two tracks simultaneously. Name the external one clearly.',                                        placeholder: 'She is trying to expose a falsified clinical trial before a drug is approved that she knows will kill people.' },
      { id: 'emotion_track',  label: 'What is the internal emotional track — the wound or belief being tested?', hint: 'The emotional track is the internal arc. Name the specific wound.',                                             placeholder: 'She has never trusted her own judgment since a mistake in residency that cost a patient their life.' },
      { id: 'crossings',      label: 'What are the crossing points — where do the two tracks meet and affect each other?', hint: 'The W shape comes from crossings where the external plot triggers an internal shift, and vice versa.',   placeholder: 'Every external setback confirms her self-doubt. Every moment she acts from instinct despite it makes the plot advance.' },
      { id: 'convergence',    label: 'Where do both tracks resolve simultaneously in the final crossing?',      hint: 'The W-Plot\'s power is that external victory and internal transformation happen together.',                         placeholder: 'She submits the evidence she\'s been afraid to trust — her own observation, no documentation — and it is enough.' },
    ],
    beats: [
      { beat: 'Opening State',        act: 1, prompt: 'What is the opening state of both the plot and the emotional arc — what is established as the baseline?',                                                                    hint: 'Establish both tracks clearly at the start. The audience needs to feel the weight of each.',                                                                                               placeholder: 'External: she is methodical, credentialed, following a tip. Internal: she double-checks everything she thinks she knows twice.' },
      { beat: 'Downward — External complication begins', act: 1, prompt: 'What external complication begins pulling the plot downward — and how does it interact with the emotional wound?',                                         hint: 'The W goes down first. External pressure triggers the internal wound.',                                                                                                                     placeholder: 'Her boss reassigns the case. She\'s told she\'s seeing things. Her old doubt surges: maybe she is.' },
      { beat: 'Crossing 1',           act: 1, prompt: 'What is the first crossing point — where does external pressure trigger an internal shift, or internal resolve push the plot upward?',                                        hint: 'A crossing is not just a parallel. It is a cause-and-effect moment between the two tracks.',                                                                                                placeholder: 'She decides to continue despite the reassignment. The external consequence: she loses institutional support. The internal shift: she is acting on her own judgment for the first time.' },
      { beat: 'Upward — False hope',  act: 2, prompt: 'What apparent success gives both the plot and the emotional arc a false summit?',                                                                                             hint: 'False hope works on both tracks: external progress that feels conclusive, internal confidence that isn\'t yet earned.',                                                                     placeholder: 'She finds corroborating evidence. She feels vindicated. She tells someone she trusts. She should not have told them.' },
      { beat: 'Crossing 2',           act: 2, prompt: 'What second crossing reveals the internal wound in the plot — how does her emotional vulnerability directly cause an external setback?',                                       hint: 'Crossing 2 shows the wound creating plot damage. This makes the internal arc feel consequential, not decorative.',                                                                          placeholder: 'The person she told leaks her findings to the trial\'s sponsor. The internal wound (she trusted someone she shouldn\'t have because she was desperate for validation) is now a plot problem.' },
      { beat: 'Downward — Midpoint reversal', act: 2, prompt: 'What is the midpoint reversal — where both tracks worsen simultaneously?',                                                                                            hint: 'The midpoint of the W-Plot is the lowest shared point. Both tracks hit bottom at the same time.',                                                                                           placeholder: 'Her findings are discredited. Her source recants. And she realizes she doesn\'t fully trust her own memory of what she saw.' },
      { beat: 'Crossing 3',           act: 3, prompt: 'What is the darkest moment — where both tracks converge at the point of maximum crisis?',                                                                                     hint: 'Crossing 3 is the crisis. External failure and internal despair meet. This is the All Is Lost.',                                                                                            placeholder: 'She has one piece of evidence left: her own firsthand observation, unverifiable, undocumented. She doesn\'t know if she believes herself.' },
      { beat: 'Upward — Internal resolution', act: 3, prompt: 'What internal resolution enables the external breakthrough?',                                                                                                         hint: 'The W-Plot\'s key rule: the internal track resolves first, which makes the external breakthrough possible.',                                                                               placeholder: 'She recalls the residency mistake in full for the first time. She sees that her judgment then was correct — and overridden. She trusts herself.' },
      { beat: 'Crossing 4',           act: 3, prompt: 'What final crossing shows external victory reflecting internal transformation?',                                                                                              hint: 'Crossing 4 is the proof that both tracks have resolved. The plot victory must specifically embody the emotional transformation.',                                                           placeholder: 'She submits the report using her observation alone. Her credibility is the only evidence. It holds.' },
      { beat: 'Resolution',           act: 3, prompt: 'What is the final state of both tracks — and how does it demonstrate that the resolution is whole, not just external?',                                                       hint: 'Both tracks must land. A resolution that only closes the plot, not the emotional arc, leaves the audience feeling unfinished.',                                                            placeholder: 'The trial is halted. She doesn\'t double-check the report she filed. She already knows it\'s right.' },
    ],
  },

  // ─── Harmon/Pixar Hybrid ────────────────────────────────────────────────────
  'harmon-pixar-hybrid': {
    displayName: 'Harmon/Pixar Hybrid',
    tagline: 'Story Circle emotional beats + Save the Cat structural beats',
    premise: [
      { id: 'character',    label: 'Who is your protagonist and what is their emotional arc (Story Circle)?',      hint: 'Map the emotional journey first: comfort zone → want → unfamiliar situation → trials → find → pay → return → change.',                       placeholder: 'A man who believes solitude is safety. Arc: he learns that being known is not the same as being vulnerable to harm.' },
      { id: 'structure',    label: 'What is the structural through-line (Save the Cat)?',                          hint: 'Now map the plot structure: opening image → set-up → catalyst → Act 2 → midpoint → all is lost → finale → final image.',                  placeholder: 'He is assigned a partner he cannot shake. The catalyst: the partner is killed. The finale: he solves it using everything he learned from her.' },
      { id: 'alignment',    label: 'Where do the emotional beats and structural beats align most powerfully?',      hint: 'The hybrid\'s power is in the alignment. Where does a structural beat land on an emotional beat for maximum impact?',                         placeholder: 'The All Is Lost structural beat aligns with the Take circle beat — he loses his partner the moment he realizes he needed her.' },
      { id: 'divergence',   label: 'Where do they usefully tension — where does one track pull against the other?', hint: 'Sometimes the emotional arc and the plot arc are ahead or behind each other by design. Name those moments.',                              placeholder: 'The Midpoint structural beat (he advances on the case) comes after the emotional return has already begun — creating dramatic irony.' },
    ],
    beats: [
      { beat: 'Story Circle: map all 8 emotional beats first', act: 1, prompt: 'Walk through all 8 Story Circle beats for your protagonist. Don\'t worry about plot yet — just the emotional arc.',                                 hint: 'You, Need, Go, Search, Find, Take, Return, Change. Name each specifically for your character.',                                                                                            placeholder: 'You: alone, functional, defended. Need: connection (he doesn\'t know it yet). Go: the partner assignment. Search: every interaction failing. Find: he trusts her. Take: she dies. Return: he solves it. Change: he asks for help at the end.' },
      { beat: 'Save the Cat: map 15 structural beats second', act: 1, prompt: 'Now map the structural beats over the emotional arc. Where does the Catalyst fall? The Midpoint? The All Is Lost?',                                    hint: 'You are building two maps and finding the alignment. Some will be obvious. Some will surprise you.',                                                                                        placeholder: 'Catalyst = the partner assignment (forced Go). Midpoint = false victory on the case + the Take beat approaching. All Is Lost = she dies (Take). Finale = he completes the case from Change.' },
      { beat: 'Align: Opening Image = You (zone of comfort)', act: 1, prompt: 'What Opening Image captures both the protagonist\'s zone of comfort and establishes the visual thesis of the film?',                                   hint: 'The Opening Image serves both frameworks: it is the "before" image AND the You beat.',                                                                                                      placeholder: 'He eats alone in a diner, facing the wall. He has a system for this. He has a system for everything.' },
      { beat: 'Align: Catalyst = Need (want something)', act: 1, prompt: 'How does the Catalyst specifically activate the character\'s Want — the need that drives the circle?',                                                       hint: 'The Catalyst should land on or adjacent to the Need beat. The disruption and the desire should be the same event.',                                                                         placeholder: 'The partner assignment forces contact — the exact thing he\'s arranged his entire life to avoid. His Need and his Catalyst are the same moment.' },
      { beat: 'Align: Break into Two = Go (unfamiliar situation)', act: 1, prompt: 'How does Act 2\'s opening — the Break into Two — coincide with crossing into the unfamiliar world of the circle?',                              hint: 'The protagonist actively enters both the new story world (Save the Cat) and the unfamiliar territory (Story Circle) at the same moment.',                                                   placeholder: 'He agrees to the partnership — the choice that defines Act 2 and constitutes his Go. He is choosing discomfort for the first time.' },
      { beat: 'Align: Fun & Games = Search (adapt, struggle)', act: 2, prompt: 'How does the Fun and Games section of Act 2 map to the Search beat — the road of trials in the unfamiliar world?',                                    hint: 'Fun and Games shows the promise of the premise. In the hybrid, this is the same period as the Search — the protagonist adapting imperfectly to the new world.',                           placeholder: 'They work cases together. He is bad at it (the partnership) and good at it (the detective work). Both tracks are active.' },
      { beat: 'Align: Midpoint = Find (get what they wanted)', act: 2, prompt: 'How does the Midpoint (false victory or defeat) correspond to the Find beat — the moment they get what they were looking for?',                        hint: 'The Find often arrives at the Midpoint as a false summit. They have what they wanted — and it immediately costs them.',                                                                      placeholder: 'He realizes he trusts her (Find) at the exact moment the case breaks wide open (false victory). The next beat is going to destroy both.' },
      { beat: 'Align: All Is Lost = Take (pay the price)', act: 2, prompt: 'How does the All Is Lost beat align with the Take beat — the moment the protagonist pays the price for what they found?',                                  hint: 'This is typically the most powerful alignment in the hybrid. Loss and structural low point are the same event.',                                                                            placeholder: 'She is killed. He loses his partner (Take) and his lowest structural point (All Is Lost) are the same moment, landing with double weight.' },
      { beat: 'Align: Break into Three = Return (back to familiar)', act: 3, prompt: 'How does Break into Three correspond to the Return beat — the protagonist moving back toward the familiar world with new knowledge?',             hint: 'Break into Three often involves a new idea that comes from the B Story — which, in the hybrid, maps to the Return beat\'s new perspective.',                                                placeholder: 'He uses her method to solve the case — the method he dismissed in Act 1 (Return). This is also the new idea that makes the Finale possible (Break into Three).' },
      { beat: 'Align: Final Image = Change (they are different)', act: 3, prompt: 'How does the Final Image prove the Change beat — that the protagonist is permanently, visibly different?',                                           hint: 'The Final Image must show transformation, not resolution. The Change beat must be legible in the single closing image.',                                                                     placeholder: 'He asks a rookie to join him for coffee. He faces the room, not the wall.' },
    ],
  },

  // ─── Freeform ───────────────────────────────────────────────────────────────
  'freeform': {
    displayName: 'Freeform',
    tagline: 'No template — your instincts are the structure',
    premise: [
      { id: 'premise',      label: 'What is the story about — in one sentence, as direct as you can make it?',    hint: 'Freeform starts from your instinct, not a structure. Say what the story is before you shape it.',               placeholder: 'A woman returns to her hometown for her father\'s funeral and cannot leave because of something she finds.' },
      { id: 'why',          label: 'Why are you the right person to write this story?',                           hint: 'In Freeform, the personal connection to the material is the structure. Name it.',                                placeholder: 'I know what it feels like to be inside a family that doesn\'t talk about things. I want to write the thing that doesn\'t get talked about.' },
      { id: 'shape',        label: 'What shape does the story have in your mind — linear, fragmented, circular?', hint: 'Freeform doesn\'t impose a shape. But you likely already have one. What is it?',                              placeholder: 'It\'s circular. She is at the funeral at the start. She is at the funeral at the end. Everything in between is the past week.' },
    ],
    beats: [
      { beat: 'Opening',      act: 1, prompt: 'How does the story begin — and why here, not somewhere else?',                                                                                                                          hint: 'In Freeform, the opening is a choice, not a formula. Name the specific reason this is the right place to start.',                                                                          placeholder: 'She is standing at the casket, alone, before the service begins, and she finds something in his pocket that stops her cold.' },
      { beat: 'Protagonist',  act: 1, prompt: 'Who is this person — specifically, in terms of what they carry into the story?',                                                                                                        hint: 'No formula. Just: who are they, what do they carry, and what do they not yet know about themselves?',                                                                                      placeholder: 'She left at 22 and never came back. She\'s been successful. She doesn\'t think leaving was a wound. She is wrong about this.' },
      { beat: 'Stakes',       act: 1, prompt: 'What does the protagonist lose if they fail — stated as concretely as possible?',                                                                                                        hint: 'Even in Freeform, stakes must be real. Name them. Not "herself" — what specific thing, relationship, or truth is at risk?',                                                                placeholder: 'If she doesn\'t find out what he found, she will spend the rest of her life carrying his version of the story, not the true one.' },
      { beat: 'Central Turn', act: 2, prompt: 'What moment changes everything — the point from which the story cannot return to what it was?',                                                                                          hint: 'Every story has a turn, even Freeform. Name the moment when the direction changes irreversibly.',                                                                                           placeholder: 'She finds his other family. Not a secret — a family. Three people. A life running alongside hers for thirty years.' },
      { beat: 'Low Point',    act: 2, prompt: 'What is the darkest moment — and what truth must now be faced that was being avoided?',                                                                                                  hint: 'The low point is not a plot beat. It is the moment the protagonist can no longer avoid what the story has been building toward.',                                                          placeholder: 'She confronts her mother. Her mother knew. Has always known. The entire foundation of her leaving is revealed to have been a lie she told herself.' },
      { beat: 'Resolution',   act: 3, prompt: 'How does the story end — and what does the ending mean, specifically?',                                                                                                                  hint: 'In Freeform, the ending is yours entirely. Name what it means, not just what happens.',                                                                                                    placeholder: 'She stays for three more days. She meets them. She doesn\'t forgive. But she stops carrying the story as if it were only hers.' },
    ],
  },

}

